#!/usr/bin/env node
/**
 * Emit `src/_contracts-bundled.ts` — the typed, tree-shakeable
 * snapshot of every monorepo contract whose `appliesTo` includes
 * this SDK. The public `CrossdeckContracts` API in `src/contracts.ts`
 * reads from this file.
 *
 * Runs BEFORE tsup so the generated module gets compiled into the
 * dist bundle. The post-tsup `emit-contracts.mjs` script writes
 * the parallel `dist/contracts.json` sidecar for non-JS consumers
 * (CI scripts, dashboards, AI assistants).
 *
 * Source of truth: `contracts/**\/*.json` at the monorepo root.
 * The generated file is auto-regenerated on every build and is
 * committed so type-checking works without running the build.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const sdkRoot = path.resolve(__dirname, "..");
const srcDir = path.join(sdkRoot, "src");
const repoRoot = path.resolve(sdkRoot, "../..");
const contractsRoot = path.join(repoRoot, "contracts");
const target = path.join(srcDir, "_contracts-bundled.ts");

const SDK_IDENTIFIER = "web";

function readSdkVersion() {
  const pkg = JSON.parse(
    fs.readFileSync(path.join(sdkRoot, "package.json"), "utf8"),
  );
  return pkg.version;
}

function collectContracts(dir) {
  const found = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) found.push(...collectContracts(full));
    else if (entry.isFile() && entry.name.endsWith(".json")) found.push(full);
  }
  return found;
}

const sdkVersion = readSdkVersion();
const bundledIn = `@cross-deck/${SDK_IDENTIFIER}@${sdkVersion}`;

const matching = [];
for (const file of collectContracts(contractsRoot)) {
  const parsed = JSON.parse(fs.readFileSync(file, "utf8"));
  if (!Array.isArray(parsed?.appliesTo)) {
    console.error(`[emit-bundled-contracts] ${file} missing appliesTo`);
    process.exit(1);
  }
  if (parsed.appliesTo.includes(SDK_IDENTIFIER)) {
    matching.push({ ...parsed, bundledIn });
  }
}
matching.sort((a, b) => a.id.localeCompare(b.id));

const header = `// AUTO-GENERATED by scripts/emit-bundled-contracts.mjs — DO NOT EDIT.
// Source of truth: contracts/**/*.json at the monorepo root.
// Regenerated on every \`npm run build\`. The public API in
// src/contracts.ts reads from this file.

import type { Contract } from "./contracts";

export const BUNDLED_IN = ${JSON.stringify(bundledIn)} as const;
export const SDK_VERSION = ${JSON.stringify(sdkVersion)} as const;

export const BUNDLED_CONTRACTS: readonly Contract[] = Object.freeze(${JSON.stringify(matching, null, 2)}) as readonly Contract[];
`;

fs.writeFileSync(target, header, "utf8");
console.log(
  `[emit-bundled-contracts] wrote ${matching.length} contracts to src/_contracts-bundled.ts (bundledIn=${bundledIn})`,
);
